window.ScenarioManager = {

  // Initialize Scenario 1
  loadScenario1() {
    // Clear all localStorage
    localStorage.removeItem('mp_collections');
    localStorage.removeItem('mp_cart');
    localStorage.removeItem('mp_favorites');
    localStorage.removeItem('mp_scenario');

    // Set scenario
    localStorage.setItem('mp_scenario', '1');

    // No collections
    localStorage.setItem('mp_collections', JSON.stringify([]));

    // Empty cart and favorites
    localStorage.setItem('mp_cart', JSON.stringify([]));
    localStorage.setItem('mp_favorites', JSON.stringify([]));

    // Set search state to "summer"
    localStorage.setItem('mp_initial_search', 'summer');

    alert('✅ Scenario 1 loaded!\nNo collections. Summer search results ready.\nRedirecting to homepage...');
    window.location.href = 'index.html?search=summer';
  },

  // Initialize Scenario 2
  loadScenario2() {
    // Keep existing collections from Scenario 1 (if any)
    const existingCollections = JSON.parse(localStorage.getItem('mp_collections') || '[]');

    // Add pre-existing collections (avoid duplicates)
    const preCollections = SCENARIO_DB.scenario2Collections;
    const allCollections = [...preCollections];

    // Add Scenario 1 collections if they exist
    existingCollections.forEach(col => {
      if (!allCollections.find(c => c.id === col.id)) {
        allCollections.push(col);
      }
    });

    localStorage.setItem('mp_collections', JSON.stringify(allCollections));
    localStorage.setItem('mp_scenario', '2');
    localStorage.removeItem('mp_initial_search');

    alert('✅ Scenario 2 loaded!\n5 collections ready (including from Scenario 1).\nRedirecting to homepage...');
    window.location.href = 'index.html';
  },

  getCurrentScenario() {
    return localStorage.getItem('mp_scenario') || '1';
  },

  // Reset — clear all localStorage and return to clean state
  reset() {
    ['mp_collections','mp_cart','mp_favorites','mp_favs','mp_scenario','mp_initial_search'].forEach(function(k) {
      localStorage.removeItem(k);
    });
    window.location.href = 'index.html';
  }
};

